import "./App.css";
import { useState, useRef } from "react";
import { PDFDocument } from "pdf-lib";
import { Viewer, Worker } from "@react-pdf-viewer/core";
import "@react-pdf-viewer/core/lib/styles/index.css";
import { defaultLayoutPlugin } from "@react-pdf-viewer/default-layout";
import "@react-pdf-viewer/default-layout/lib/styles/index.css";

function App() {
  const [files, setFile] = useState([]);
  const [mergedFile, setMergeFile] = useState();
  const dragItem = useRef();
  const dragOverItem = useRef();
  // const [mergedFileUrl, setMergedFileUrl] = useState();
  const defaultLayoutPluginInstance = defaultLayoutPlugin();

  const uploadFile = async (e) => {

    await setFile([...files, ...e.target.files]);
  };
  const readFileAsync = (file) => {
    return new Promise((resolve, reject) => {
      let reader = new FileReader();
      reader.onload = () => {
        resolve(reader.result);
      };
      reader.onerror = reject;
      reader.readAsArrayBuffer(file);
    });
  };

  const downloadMerged = () => {
    // const link = document.createElement('a');
    // const link = document.getElementById("link");
    // link.download = "MergedPdf";
    // let binaryData = [];
    // binaryData.push(mergedFile);
    // link.href = URL.createObjectURL(new Blob(binaryData, { type: "application/pdf" }))
    // window.location.href = URL.createObjectURL(
    //   new Blob(binaryData, { type: "application/pdf" })
    // );
    setFile([]);
    setMergeFile();
  };

  const mergeFiles = async () => {
    let doc = await PDFDocument.create();

    files.forEach(async (file)=>{
      const pdf = await PDFDocument.load(await readFileAsync(file));

      const pdfInd = await doc.copyPages(
        pdf,
        pdf.getPageIndices()
      );

      for (const page of pdfInd) {
        doc.addPage(page);
      }

      const mergedPdfFile = await doc.save();
      setMergeFile(mergedPdfFile);
    })

    // let pdfFirst = await PDFDocument.load(await readFileAsync(files[0]));
    // let pdfSecond = await PDFDocument.load(await readFileAsync(files[1]));

    // const pdfFirstInd = await doc.copyPages(
    //   pdfFirst,
    //   pdfFirst.getPageIndices()
    // );

    // for (const page of pdfFirstInd) {
    //   doc.addPage(page);
    // }

    // const pdfSecondInd = await doc.copyPages(
    //   pdfSecond,
    //   pdfSecond.getPageIndices()
    // );

    // for (const page of pdfSecondInd) {
    //   doc.addPage(page);
    // }


    // creates a local url for pdf
    // setMergedFileUrl(URL.createObjectURL(new Blob([mergedPdfFile], { type: "application/pdf" })));
  };
  const dragStart = (e, position) => {
    dragItem.current = position;
    console.log(e.target.innerHTML);
  };
 
  const dragEnter = (e, position) => {
    dragOverItem.current = position;
    console.log(e.target.innerHTML);
  };

  const drop = (e) => {
    const copyListItems = [...files];
    const dragItemContent = copyListItems[dragItem.current];
    copyListItems.splice(dragItem.current, 1);
    copyListItems.splice(dragOverItem.current, 0, dragItemContent);
    dragItem.current = null;
    dragOverItem.current = null;
    console.log("copy list items",copyListItems);
    setFile(copyListItems);
  };

  //new Uint8Array( pdfBytes ); converts pdf into bite8 Array
  return (
    <div className="App">
      <input type="file" onChange={uploadFile} multiple={true}></input>
      <button onClick={mergeFiles}>Merge</button>
      <button onClick={downloadMerged}>Reset</button>
      <ul className="pdf-box">
        {
          files.map((item,index)=><li className="pdf-list" key={index} draggable onDragStart={(e)=>dragStart(e,index)} onDragEnter={(e)=>dragEnter(e,index)} onDragEnd={drop}>{item.name}</li>)
        }
      </ul>
      <div className="viewer">
      {mergedFile && (
        <Worker workerUrl="https://unpkg.com/pdfjs-dist@2.14.305/build/pdf.worker.min.js">
          <Viewer fileUrl={new Uint8Array(mergedFile)} plugins={[defaultLayoutPluginInstance]}/>
        </Worker>
      )}
      </div>
    </div>
  );
}

export default App;
